firmware_template.source:
#include "wifi_provisioning.h"
#include <WiFiManager.h>

static WiFiManager wm;
static bool configured = false;

static void save_callback() {
  configured = true;
  Serial.println("[wifi_prov] Credentials saved");
}

void wifi_prov_setup(const char* ap_name, const char* ap_password) {
  wm.setSaveConfigCallback(save_callback);
  wm.setConfigPortalTimeout(180);
  wm.setConnectTimeout(30);
  if (!wm.autoConnect(ap_name, ap_password)) {
    Serial.println("[wifi_prov] Portal timeout — restarting");
    ESP.restart();
  }
  Serial.printf("[wifi_prov] Connected: %s\n", WiFi.localIP().toString().c_str());
}

bool wifi_prov_is_connected() {
  return WiFi.status() == WL_CONNECTED;
}

void wifi_prov_reset() {
  wm.resetSettings();
  ESP.restart();
}

String wifi_prov_get_ip() {
  return WiFi.localIP().toString();
}
